//! # Actr - Actor-RTC Framework
//!
//! Actr is a distributed Actor framework based on WebRTC for building real-time communication systems.
//!
//! ## Quick Start
//!
//! ```rust,ignore
//! use actr::prelude::*;
//!
//! #[derive(Default)]
//! struct MyActor;
//!
//! // MessageDispatcher is generated by actr-cli codegen
//! #[async_trait]
//! impl Workload for MyActor {
//!     type Dispatcher = MyActorDispatcher;
//!
//!     async fn on_start<C: Context>(&self, ctx: &C) -> ActorResult<()> {
//!         // Use logging as needed
//!         Ok(())
//!     }
//! }
//! ```

#![warn(missing_docs)]

// ============================================================================
// Protocol - 核心协议类型
// ============================================================================

/// Protocol 模块 - 核心协议定义
pub use actr_protocol as protocol;

// 重新导出常用的协议类型
pub use actr_protocol::{
    ActorResult, ActrError, ActrId, ActrType, PayloadType, RpcEnvelope, RpcRequest,
};

// ============================================================================
// Framework - 框架核心抽象
// ============================================================================

/// Framework 模块 - 框架核心抽象
pub use actr_framework as framework;

// 重新导出框架核心类型
pub use actr_framework::{Context, MessageDispatcher, Workload};

// ============================================================================
// Runtime - 运行时 (可选)
// ============================================================================

#[cfg(feature = "runtime")]
/// Runtime 模块 - ActorSystem 运行时
pub use actr_runtime as runtime;

// ============================================================================
// Config - 配置支持 (可选)
// ============================================================================

#[cfg(feature = "config")]
/// Config 模块 - 配置文件解析
pub use actr_config as config;

// ============================================================================
// Prelude - 常用导入
// ============================================================================

/// Prelude 模块 - 包含最常用的类型和 trait
///
/// 推荐在应用代码中使用 `use actr::prelude::*;` 来导入所有必要的类型。
pub mod prelude {
    // 协议层 - 核心类型
    pub use crate::protocol::{
        ActorResult, ActrError, ActrId, ActrType, PayloadType, RpcEnvelope, RpcRequest,
    };

    // 框架层 - 核心 trait 和类型
    pub use crate::framework::{Context, MessageDispatcher, Workload};

    // 运行时
    #[cfg(feature = "runtime")]
    pub use crate::runtime;

    // 配置
    #[cfg(feature = "config")]
    pub use crate::config;

    // 常用 trait 和类型
    pub use async_trait::async_trait;
    pub use std::sync::Arc;
}
